      osc("square", 523, 523, 0.12, 0.055*mv, 0);
      osc("square", 659, 659, 0.12, 0.055*mv, 0.10);
      osc("square", 784, 784, 0.14, 0.06*mv, 0.20);
      osc("triangle", 1047, 1047, 0.28, 0.07*mv, 0.30);
