    const p = LORE_STONES[id]; const sx = p.tx*TILE, sy = p.ty*TILE;
    const got = !!(S.lore && S.lore[id]);
    ctx.fillStyle = "rgba(0,0,0,.16)"; ctx.beginPath(); ctx.ellipse(sx+TILE/2, sy+TILE-3, 11, 4, 0, 0, 7); ctx.fill();
