      if (Math.floor(t*3+sx)%3===0){ ctx.fillStyle="#ffffff"; const gy=sy-6+((Math.floor(t*2)+Math.floor(sx))%12); ctx.fillRect(sx-6+((Math.floor(t*4))%12),gy,1,1); }
