document.getElementById("version-label")?.addEventListener("keydown", (e:any) => { if (e.key==="Enter"||e.key===" ") { e.preventDefault(); openRoadmap(); } });
syncJourneyBtn(); syncJournalBtn();
window.addEventListener("keydown", e => {
  const typing = /^(INPUT|TEXTAREA|SELECT)$/.test((e.target as any)?.tagName||"");
  if (!typing) setInputMethod('keyboard');   // keyboard is now the active input (req 11)
  // ---- controller-equivalent keyboard nav (works everywhere, incl. modals) ----
  if (!typing){
    // In an open-world view (village or an interior) with nothing focused, the
    // arrow keys WALK the character (so ArrowDown leaves a building — req 3). In
    // menus / modals / the title, they navigate UI focus instead (never swallowed).
    const _worldNav = (S.tab==="village" || INTERIOR_TABS.has(S.tab)) && !_topModal() && !_paused && !_uiFocusEl && !_titleUp();
    if (e.key==="ArrowUp"||e.key==="ArrowDown"||e.key==="ArrowLeft"||e.key==="ArrowRight"){
      if (_worldNav){ e.preventDefault(); VKEYS[e.key] = true; return; }
      e.preventDefault(); moveUiFocus((e.key==="ArrowUp"||e.key==="ArrowLeft") ? -1 : 1); return;
    }
    if (e.key==="Tab"){ e.preventDefault(); moveUiFocus(e.shiftKey ? -1 : 1); return; }
    if (e.key==="Enter"){ if (uiConfirm()){ e.preventDefault(); return; } }
    if (e.key==="Escape" || e.key==="Backspace"){
      if (uiBack()){ e.preventDefault(); return; }
      // In an interior, Escape/Back opens the small RECOVERY menu (Resume / Leave
      // building / Settings) — a guaranteed non-reload way out (req 5/7).
      if (e.key==="Escape" && INTERIOR_TABS.has(S.tab) && S.tab!=="village" && !_topModal() && !_titleUp()){ e.preventDefault(); openRecoveryMenu(); return; }
      if (e.key==="Escape" && !_topModal() && !_titleUp()){ e.preventDefault(); openPauseMenu(); return; }
    }
    // category (LB/RB) + screen (LT/RT) keyboard equivalents, and Objectives (View)
    if (e.key==="["){ e.preventDefault(); switchNavCategory(-1); return; }
    if (e.key==="]"){ e.preventDefault(); switchNavCategory(1); return; }
    if (e.key==="-" || e.key==="_"){ e.preventDefault(); switchScreen(-1); return; }
    if (e.key==="=" || e.key==="+"){ e.preventDefault(); switchScreen(1); return; }
    if (e.key==="o"||e.key==="O"){ e.preventDefault(); openObjectives(); return; }
  }
  if (typing) return;
  if ((e.key==="j"||e.key==="J")){ openJourney(); return; }
  if ((e.key==="i"||e.key==="I")){ toggleInventory(); return; }
  // M3: Space swings the current gathering action (keyboard/accessibility for Active Swing)
  if (e.key===" "){
    if (S.action && SWING_SKILLS.has(S.action.skill)){ e.preventDefault(); swing(); return; }
  }
  // E / Enter — the keyboard "deliberate direct interaction" control (mirrors
  // controller A): interact with the highlighted (or nearest) in-range target.
  if ((e.key==="e"||e.key==="E"||e.key==="Enter") && !_topModal() && !_paused){
    if (S.tab==="village" || INTERIOR_TABS.has(S.tab)){ e.preventDefault(); gpInteract(); return; }
  }
  // WASD walks the avatar in world views (arrows are reserved for UI focus above).
  if (_topModal() || _paused) return;
  if (S.tab !== "village" && !INTERIOR_TABS.has(S.tab)) return;
  if (["a","d","w","s"].includes(e.key)) VKEYS[e.key] = true;
});
window.addEventListener("keyup", e => { VKEYS[e.key] = false; });
// A real pointer/touch press makes the pointer the active input method (req 11):
// hides the controller/keyboard prompt bar so mouse/touch players get a clean HUD.
window.addEventListener("pointerdown", () => setInputMethod('pointer'), { passive:true });
// Autoplay-safe audio bootstrap. HTMLAudio needs a user activation to start, and a
// rejected play() is never retried — so returning players (who skip the title) and
// any deferred start would get silence. On the FIRST real gesture, unlock + start the
// zone music (respecting the music setting); retry on later gestures until it takes.
let _audioBootstrapped = false;
function _bootstrapAudio(){
  if (_audioBootstrapped) return;
  if (!(S.settings && S.settings.music)) return;   // music off: try again on a later gesture
  try{ MUSIC.unlocked = true; MUSIC.setVol(volLevel()); updateMusicZone(); _audioBootstrapped = true; }
  catch(e){ _audioBootstrapped = false; }
}
["pointerdown","keydown","touchstart"].forEach(ev => window.addEventListener(ev, _bootstrapAudio, { passive:true }));
